const input = $('Execute Workflow Trigger').first().json;

// Parse attachments - may arrive as JSON string from toolWorkflow
let attachments = input.attachments || [];
if (typeof attachments === 'string') {
  try {
    attachments = JSON.parse(attachments);
  } catch(e) {
    attachments = [];
  }
}
if (!Array.isArray(attachments)) attachments = [];

const content = input.content || input.query || '';
const platform = input.platform || 'discord';
const context = input.context || '';
const messageContent = input.message_content || '';

let mediaType = 'unknown';
let mediaUrl = null;
let mediaUrls = [];  // For multi-image support
let videoId = null;
let filename = null;
let needsTelegramDownload = false;
let fileMimeType = null;
let telegramFileId = null;

// Check attachments first
if (attachments.length > 0) {
  // Check first attachment for type classification
  const att = attachments[0];

  // Normalize content type - guild adapter stores as 'type', others use 'content_type'/'mime_type'
  const ct = (att.content_type || att.mime_type || att.type || '').toLowerCase();
  const fname = (att.filename || att.file_name || '').toLowerCase();

  if (ct.startsWith('image/') || /\.(jpg|jpeg|png|webp|gif)$/i.test(fname)) {
    mediaType = 'image';
    if (platform === 'telegram' || att.file_id) {
      needsTelegramDownload = true;
      telegramFileId = att.file_id;
      fileMimeType = ct || 'image/jpeg';
      mediaUrl = att.url || att.proxy_url;
    } else {
      mediaUrl = att.url || att.proxy_url;
      // Collect ALL image attachment URLs for multi-image support
      for (const a of attachments) {
        const aCt = (a.content_type || a.mime_type || a.type || '').toLowerCase();
        const aFname = (a.filename || a.file_name || '').toLowerCase();
        if (aCt.startsWith('image/') || /\.(jpg|jpeg|png|webp|gif)$/i.test(aFname)) {
          const url = a.url || a.proxy_url;
          if (url) mediaUrls.push(url);
        }
      }
    }
    filename = att.filename || att.file_name || 'image';
  } else if (ct === 'application/pdf' || /\.pdf$/i.test(fname)) {
    mediaType = 'pdf';
    mediaUrl = att.url || att.proxy_url;
    filename = att.filename || att.file_name || 'document.pdf';
  } else if (ct === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' || /\.docx$/i.test(fname)) {
    mediaType = 'docx';
    mediaUrl = att.url || att.proxy_url;
    filename = att.filename || att.file_name || 'document.docx';
  } else if (ct === 'text/plain' || /\.txt$/i.test(fname)) {
    mediaType = 'txt';
    mediaUrl = att.url || att.proxy_url;
    filename = att.filename || att.file_name || 'document.txt';
  }
}

// Check content for YouTube URL
if (mediaType === 'unknown') {
  const ytMatch = content.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([a-zA-Z0-9_-]{11})/);
  if (ytMatch) {
    mediaType = 'youtube';
    videoId = ytMatch[1];
  }
}

// Check context and message_content for YouTube URL
for (const field of [context, messageContent]) {
  if (mediaType === 'unknown' && field) {
    const ytMatch = field.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([a-zA-Z0-9_-]{11})/);
    if (ytMatch) {
      mediaType = 'youtube';
      videoId = ytMatch[1];
      break;
    }
  }
}

// Check query field for file URL - check document extensions BEFORE image catch-all
if (mediaType === 'unknown' && input.query) {
  const q = input.query;

  // Also check query for YouTube URLs
  const ytMatch = q.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([a-zA-Z0-9_-]{11})/);
  if (ytMatch) {
    mediaType = 'youtube';
    videoId = ytMatch[1];
  } else if (/\.pdf(\?|$)/i.test(q)) {
    mediaType = 'pdf';
    const urlMatch = q.match(/(https?:\/\/\S+)/);
    mediaUrl = urlMatch ? urlMatch[1] : q;
    filename = (mediaUrl.split('/').pop() || 'document').split('?')[0];
  } else if (/\.docx(\?|$)/i.test(q)) {
    mediaType = 'docx';
    const urlMatch = q.match(/(https?:\/\/\S+)/);
    mediaUrl = urlMatch ? urlMatch[1] : q;
    filename = (mediaUrl.split('/').pop() || 'document').split('?')[0];
  } else if (/\.txt(\?|$)/i.test(q)) {
    mediaType = 'txt';
    const urlMatch = q.match(/(https?:\/\/\S+)/);
    mediaUrl = urlMatch ? urlMatch[1] : q;
    filename = (mediaUrl.split('/').pop() || 'document').split('?')[0];
  } else if (/\.(jpg|jpeg|png|gif|webp)(\?|$)/i.test(q) || /cdn\.discordapp\.com\/attachments\//i.test(q)) {
    // Image catch-all - Discord CDN URLs without a document extension
    mediaType = 'image';
    const urlMatch = q.match(/(https?:\/\/\S+)/);
    mediaUrl = urlMatch ? urlMatch[1] : q;
    mediaUrls = [mediaUrl];
    filename = (mediaUrl.split('/').pop() || 'image').split('?')[0];
  }
}

return [{
  json: {
    mediaType,
    mediaUrl,
    mediaUrls,  // Array of all image URLs for multi-image
    videoId,
    filename,
    needsTelegramDownload,
    telegramFileId,
    fileMimeType,
    platform,
    content,
    context,
    person_id: input.person_id,
    source_channel: input.source_channel,
    conversation_privacy: input.conversation_privacy
  }
}];

const input = $('Detect Media Type').first().json;

const VISION_MODELS = [
  'anthropic/claude-sonnet-4.6',  // best vision + language quality
  'google/gemini-2.5-pro',         // excellent vision, different provider
  'openai/gpt-4o'                  // reliable fallback, third provider
];

const VISION_SYSTEM_PROMPT = "When an image contains text (screenshots, documents, chat logs, terminal output, code, error messages, etc.), transcribe ALL visible text verbatim first in a clearly marked section, then provide your analysis or description. If the image is purely visual with no text, describe it in detail.";

// Collect image URLs - prefer mediaUrls array for multi-image, fall back to single mediaUrl
let imageUrls = (input.mediaUrls && input.mediaUrls.length > 0) ? input.mediaUrls : [];
if (imageUrls.length === 0 && input.mediaUrl) {
  imageUrls = [input.mediaUrl];
}

const imageCount = imageUrls.length;
let prompt = input.context || input.content || 'Describe this image in detail.';
if (imageCount > 1) {
  prompt = `There are ${imageCount} images attached. ${prompt}`;
}

return [{json: {
  vision_models: VISION_MODELS,
  current_model_index: 0,
  prompt,
  vision_system_prompt: VISION_SYSTEM_PROMPT,
  imageUrl: imageUrls[0] || input.mediaUrl,  // Keep for backwards compat (Telegram path)
  imageUrls,  // Full array for multi-image
  imageCount,
  platform: input.platform,
  person_id: input.person_id,
  content: input.content,
  filename: input.filename,
  mediaType: input.mediaType,
  needsTelegramDownload: input.needsTelegramDownload,
  telegramFileId: input.telegramFileId,
  fileMimeType: input.fileMimeType,
  max_tokens: 4096
}}];

// Get the original vision request data
const visionData = $('Build Vision Request').first().json;

// Get binary data from the downloaded file
// n8n stores binary data in the items[0].binary object
const items = $input.all();
const item = items[0];
const binaryData = item.binary;

if (!binaryData) {
  // Fallback - cannot get binary data
  return [{json: {
    ...visionData,
    imageUrl: null,
    _telegramDownloadFailed: true
  }}];
}

const binaryKey = Object.keys(binaryData)[0];
const b64 = binaryData[binaryKey].data;
const mimeType = visionData.fileMimeType || 'image/jpeg';

return [{json: {
  ...visionData,
  imageUrl: `data:${mimeType};base64,${b64}`
}}];

const req = $json;
// Build content array with text prompt + all image URLs
const content = [{type: 'text', text: req.prompt}];

const imageUrls = req.imageUrls || [];
if (imageUrls.length > 0) {
  for (const url of imageUrls) {
    content.push({type: 'image_url', image_url: {url}});
  }
} else if (req.imageUrl) {
  // Fallback to single imageUrl (Telegram base64 path)
  content.push({type: 'image_url', image_url: {url: req.imageUrl}});
}

const body = {
  model: req.vision_models[0],
  messages: [
    {role: 'system', content: req.vision_system_prompt},
    {role: 'user', content}
  ],
  max_tokens: req.max_tokens || 1024
};
return [{json: {
  vision_request_body: JSON.stringify(body),
  _vision_request: req
}}];

const response = $input.first().json;
// The Build Vision Req node embedded _vision_request - read from it
let req;
try {
  req = $('Build Vision Req Model 1').first().json._vision_request;
} catch(e) {
  req = {vision_models: ['google/gemini-2.0-flash-exp:free', 'google/gemini-flash-1.5', 'anthropic/claude-3-haiku'], imageUrl: '', prompt: ''};
}

if (response && !response.error && response.choices && response.choices.length > 0) {
  return [{json: {
    vision_description: response.choices[0].message.content,
    model_used: response.model || req.vision_models[0],
    vision_error: false,
    _vision_request: req
  }}];
}

return [{json: {
  _model1_failed: true,
  _error1: (response && response.error && response.error.message) || (response && response.message) || 'No choices returned',
  _vision_request: req
}}];

const req = $json;
// Build content array with text prompt + all image URLs
const content = [{type: 'text', text: req.prompt}];

const imageUrls = req.imageUrls || [];
if (imageUrls.length > 0) {
  for (const url of imageUrls) {
    content.push({type: 'image_url', image_url: {url}});
