const response = $input.first().json;
let req;
try {
  req = $('Build Vision Req Model 2').first().json._vision_request;
} catch(e) {
  try { req = $('Build Vision Req Model 1').first().json._vision_request; } catch(e2) { req = {}; }
}

if (response && !response.error && response.choices && response.choices.length > 0) {
  return [{json: {
    vision_description: response.choices[0].message.content,
    model_used: response.model || (req.vision_models && req.vision_models[1]) || 'google/gemini-flash-1.5',
    vision_error: false,
    _vision_request: req
  }}];
}

return [{json: {
  _model2_failed: true,
  _error2: (response && response.error && response.error.message) || 'No choices returned',
  _vision_request: req
}}];

const req = $json;
// Build content array with text prompt + all image URLs
const content = [{type: 'text', text: req.prompt}];

const imageUrls = req.imageUrls || [];
if (imageUrls.length > 0) {
  for (const url of imageUrls) {
    content.push({type: 'image_url', image_url: {url}});
  }
} else if (req.imageUrl) {
  // Fallback to single imageUrl (Telegram base64 path)
  content.push({type: 'image_url', image_url: {url: req.imageUrl}});
}

const body = {
  model: req.vision_models[2],
  messages: [
    {role: 'system', content: req.vision_system_prompt},
    {role: 'user', content}
  ],
  max_tokens: req.max_tokens || 1024
};
return [{json: {
  vision_request_body: JSON.stringify(body),
  _vision_request: req
}}];

const response = $input.first().json;
let req;
try {
  req = $('Build Vision Req Model 3').first().json._vision_request;
} catch(e) { req = {}; }

if (response && !response.error && response.choices && response.choices.length > 0) {
  return [{json: {
    vision_description: response.choices[0].message.content,
    model_used: response.model || (req.vision_models && req.vision_models[2]) || 'anthropic/claude-3-haiku',
    vision_error: false,
    _vision_request: req
  }}];
}

return [{json: {
  vision_description: null,
  vision_error: true,
  model_tried: (req.vision_models && req.vision_models[2]) || 'anthropic/claude-3-haiku',
  _vision_request: req
}}];

const detect = $('Detect Media Type').first().json;
const visionResult = $json;

let result;
if (visionResult.vision_error || visionResult.vision_description === null) {
  result = "I tried to analyze that image but ran into trouble with the vision models right now. You might want to try again in a moment.";
} else {
  result = visionResult.vision_description;
}

const imageCount = (detect.mediaUrls && detect.mediaUrls.length > 0) ? detect.mediaUrls.length : 1;

return [{json: {
  result,
  media_type: 'image',
  filename: detect.filename || 'image',
  model_used: visionResult.model_used || null,
  image_count: imageCount
}}];

const detect = $('Detect Media Type').first().json;
// Extract From File outputs text in $json.text
let text = $json.text || $json.data || '';
if (typeof text !== 'string') text = String(text);
if (text.length > 8000) {
  text = text.substring(0, 8000) + '\n\n[Content truncated — showing first 8000 characters]';
}
return [{json: {
  extracted_text: text,
  media_type: 'pdf',
  filename: detect.filename || 'document.pdf',
  content: detect.content,
  person_id: detect.person_id
}}];

const detect = $('Detect Media Type').first().json;
// @mazix converter outputs text in files[0].text
let text = ($json.files && $json.files[0] && $json.files[0].text) || $json.text || $json.data || $json.content || $json.body || '';
if (typeof text !== 'string') {
  try { text = JSON.stringify(text); } catch(e) { text = String(text); }
}
if (text.length > 8000) {
  text = text.substring(0, 8000) + '\n\n[Content truncated — showing first 8000 characters]';
}
return [{json: {
  extracted_text: text,
  media_type: 'docx',
  filename: detect.filename || 'document.docx',
  content: detect.content,
  person_id: detect.person_id
}}];

const detect = $('Detect Media Type').first().json;
let text = $json.text || $json.data || '';
if (typeof text !== 'string') text = String(text);
if (text.length > 8000) {
  text = text.substring(0, 8000) + '\n\n[Content truncated — showing first 8000 characters]';
