return [{json: {
  result: "I received a file but I'm not sure how to process it. I can handle images (JPG, PNG, WEBP), documents (PDF, DOCX, TXT), and YouTube links — want to try one of those?",
  media_type: 'unknown',
  filename: 'unknown'
}}];

const data = $json;
const isYoutube = data.is_youtube;
const filename = data.filename || 'document';
const content = data.content || '';
const extractedText = data.extracted_text || '';

let systemPrompt, userMessage;

if (isYoutube) {
  systemPrompt = "You are Aerys. Summarize the following YouTube transcript for the user. Be natural and conversational, highlighting the key points. Use first person when appropriate.";
  userMessage = `Video: ${data.youtube_title || filename}\n\nTranscript:\n${extractedText}`;
} else {
  systemPrompt = "You are Aerys. Synthesize the following extracted content in response to the user's request. Be concise and natural. If the user asked a question, answer it using the content.";
  userMessage = content
    ? `User asked: ${content}\n\nExtracted content from ${filename}:\n${extractedText}`
    : `Here is the extracted content from ${filename}:\n${extractedText}`;
}

const body = {
  model: 'anthropic/claude-sonnet-4.6',
  messages: [
    {role: 'system', content: systemPrompt},
    {role: 'user', content: userMessage}
  ],
  max_tokens: 2000
};

return [{json: {
  synthesis_request_body: JSON.stringify(body),
  _media_type: data.media_type,
  _filename: filename,
  _person_id: data.person_id
}}];

const response = $input.first().json;
let reqData;
try {
  reqData = $('Build LLM Synthesis Request').item.json;
} catch(e) {
  reqData = {_media_type: 'document', _filename: 'document'};
}

let result;
if (response && !response.error && response.choices && response.choices.length > 0) {
  result = response.choices[0].message.content;
} else {
  result = `I extracted the content from the ${reqData._media_type || 'document'} but had trouble synthesizing a response right now.`;
}

return [{json: {
  result,
  media_type: reqData._media_type || 'document',
  filename: reqData._filename || 'document'
}}];

// This node collects from all result paths
// result field is already set
const data = $json;
return [{json: {
  result: data.result,
  media_type: data.media_type,
  filename: data.filename
}}];

const detect = $('Detect Media Type').first().json;
const videoUrl = 'https://www.youtube.com/watch?v=' + detect.videoId;

const body = JSON.stringify({
  contents: [{
    parts: [
      {text: "Summarize this YouTube video. Be natural and conversational, highlighting the key points, main ideas, and any important details. Give a thorough but readable summary."},
      {file_data: {file_uri: videoUrl}}
    ]
  }],
  generationConfig: {
    maxOutputTokens: 8192
  }
});

return [{json: {
  requestBody: body,
  videoId: detect.videoId,
  content: detect.content,
  person_id: detect.person_id
}}];

const response = $json;
const req = $('Build Gemini YouTube Request').first().json;

let result;
if (response.candidates && response.candidates[0]?.content?.parts?.[0]?.text) {
  result = response.candidates[0].content.parts[0].text;
} else if (response.error) {
  result = `I wasn't able to pull up that video — ${response.error.message || 'something went wrong on my end'}.`;
} else {
  result = "I wasn't able to process that video — it might be private, age-restricted, or not yet indexed.";
}

return [{json: {
  result,
  media_type: 'youtube',
  filename: 'youtube_video',
  person_id: req.person_id
}}];
